"""ToolSpec 브릿지 — 외부 도구 스키마를 mantis ToolSpec으로 변환."""

from __future__ import annotations

import inspect
from typing import Any, Callable

from mantis.tools.decorator import ToolSpec


def toolspec_from_openai_schema(
    schema: dict[str, Any],
    executor_fn: Callable,
) -> ToolSpec:
    """OpenAI function-calling 스키마 + 실행 함수 → ToolSpec 변환.

    외부 시스템의 도구를 mantis ToolRegistry에 주입할 때 사용.

    Args:
        schema: OpenAI function-calling 스키마.
            {"type": "function", "function": {"name": ..., "description": ..., "parameters": ...}}
            또는 {"name": ..., "description": ..., "parameters": ...} (function 키 생략 가능)
        executor_fn: 도구 실행 함수. sync/async 모두 지원.

    Returns:
        ToolSpec
    """
    func_def = schema.get("function", schema)
    name = func_def["name"]
    description = func_def.get("description", "")
    params_schema = func_def.get("parameters", {})

    # OpenAI parameters 형식 → mantis parameters 형식 변환
    properties = params_schema.get("properties", {})
    required = set(params_schema.get("required", []))

    parameters: dict[str, Any] = {}
    for param_name, prop in properties.items():
        param: dict[str, Any] = {
            "type": prop.get("type", "string"),
            "description": prop.get("description", ""),
        }
        if param_name not in required:
            param["optional"] = True
        if "enum" in prop:
            param["enum"] = prop["enum"]
        if "items" in prop:
            param["items"] = prop["items"]
        parameters[param_name] = param

    return ToolSpec(
        name=name,
        description=description,
        parameters=parameters,
        fn=executor_fn,
        is_async=inspect.iscoroutinefunction(executor_fn),
    )
